export const CATEGORY_META = {
  salon: { label: "Салон", icon: "💇" },
  barber: { label: "Үсчин", icon: "✂" },
  beauty: { label: "Гоо сайхан", icon: "💄" },
  billiard: { label: "Бильярд", icon: "🎱" },
  restaurant: { label: "Ресторан", icon: "🍽" },
  resort: { label: "Амралт", icon: "🏞" },
};

export const CATEGORY_OPTIONS = [
  { key: "all", label: "Бүгд", icon: "🧭" },
  ...Object.entries(CATEGORY_META).map(([key, meta]) => ({ key, ...meta })),
];

export const STAFF_BASED = ["salon", "barber", "beauty"];
export const TABLE_BASED = ["billiard", "restaurant"];

export function getBookingMode(category) {
  if (STAFF_BASED.includes(category)) return "staff";
  if (TABLE_BASED.includes(category)) return "table";
  return "basic";
}
